#include <vector>
#include <algorithm>

void adaptive_sort(std::vector<int>& arr) {
    const size_t n = arr.size();
    if (n < 2) return;

    // Fast check for already sorted data: O(1) best case for random, O(N) for sorted.
    if (std::is_sorted(arr.begin(), arr.end())) {
        return;
    }

    // Fast check for reverse-sorted data: O(N) check followed by O(N) reversal.
    if (std::is_sorted(arr.rbegin(), arr.rend())) {
        std::reverse(arr.begin(), arr.end());
        return;
    }

    // Use Insertion Sort for very small arrays to avoid the overhead of Introsort partitioning.
    // Threshold 24 is a common sweet spot for modern CPUs.
    if (n < 24) {
        for (size_t i = 1; i < n; ++i) {
            int key = arr[i];
            size_t j = i;
            while (j > 0 && arr[j - 1] > key) {
                arr[j] = arr[j - 1];
                --j;
            }
            arr[j] = key;
        }
        return;
    }

    // Default to the highly optimized Introsort (hybrid of Quicksort, Heapsort, and Insertion Sort).
    std::sort(arr.begin(), arr.end());
}

